        [Test]
        public async Task Select_ShouldScrollToSelectedItemOnOpen()
        {
            // Render a select with a pre-selected value (Item 5)
            var comp = Context.Render<SelectScrollToSelectedTest>();
            var select = comp.FindComponent<MudSelect<string>>();

            // Verify initial value is set
            select.Instance.ReadValue.Should().Be("5");

            // Open the dropdown
            IElement Input() => comp.Find("div.mud-input-control");
            IElement Menu() => comp.Find("div.mud-popover");

            await Input().MouseDownAsync();

            // Wait for the popover to open
            await comp.WaitForAssertionAsync(() => Menu().ClassList.Should().Contain("mud-popover-open"));

            // Verify items are rendered
            await comp.WaitForAssertionAsync(() => comp.FindAll("div.mud-list-item").Count.Should().Be(10));

            // Verify the select has items in its Items collection
            await comp.WaitForAssertionAsync(() => select.Instance.Items.Count.Should().Be(10));

            // Verify the activeItemId is set to the selected item (Item 5)
            // The activeItemId should not be null after opening
            var items = comp.FindAll("div.mud-list-item");
            var selectedItem = items.FirstOrDefault(i => i.TextContent.Trim() == "5");
            selectedItem.Should().NotBeNull("Item 5 should be rendered in the dropdown");

            // Close and verify
            await Input().MouseDownAsync();
            await comp.WaitForAssertionAsync(() => Menu().ClassList.Should().NotContain("mud-popover-open"));
        }
    }
}

