@namespace MudBlazor
@typeparam T
@inherits MudComponentBase

@if (!HideContent)
{
    <MudListItem @attributes="GetUserAttributes()" Value="@ItemId" id="@ItemId" OnClick="this.AsNonRenderingEventHandler(OnClickHandleAsync)" OnClickPreventDefault="true" Icon="@CheckBoxIcon" Disabled="@Disabled" Class="@GetCssClasses()" Style="@Style">
        @if (ChildContent is not null)
        {
            @ChildContent
        }
        else
        {
            @DisplayString
        }
    </MudListItem>
}

@namespace MudBlazor
@inherits MudComponentBase
@typeparam T

<MudElement HtmlTag="@HtmlTag"
            id="@ElementId"
            Class="@Classname"
            Style="@Style"
            tabindex="@GetTabIndex()"
            role="@GetRole()"
            aria-selected="@GetAriaSelected()"
            aria-expanded="@GetAriaExpanded()"
            @attributes="UserAttributes"
            @onclick="OnClickHandlerAsync"
            @onfocus="OnFocusAsync"
            @onkeydown="HandleKeyDownAsync"
            href="@Href"
            target="@Target"
            PreventDefault="@GetPreventDefault()"
            ClickPropagation="@GetClickPropagation()"
            @bind-Ref="_elementReference">

    @if (AvatarContent is not null)
    {
        <div class="mud-list-item-avatar">
            @AvatarContent
        </div>
    }
    else if (!string.IsNullOrWhiteSpace(Icon))
    {
        <div class="mud-list-item-icon">
            <MudIcon Icon="@Icon"
                     Disabled="@GetDisabled()"
                     Color="@IconColor"
                     Size="@IconSize" />
        </div>
    }

    @if (MultiSelection && NestedList is null)
    {
        <MudCheckBox T="bool?"
                     TriState
                     ReadOnly="@ReadOnly"
                     KeyboardEnabled="false"
                     Class="mud-list-item-checkbox my-n2 ms-n2"
                     Disabled="@GetDisabled()"
                     CheckedIcon="@GetCheckedIcon()"
                     UncheckedIcon="@GetUncheckedIcon()"
                     IndeterminateIcon="@GetIndeterminateIcon()"
                     Color="@GetCheckBoxColor()"
                     UncheckedColor="@GetCheckBoxColor()"
                     @bind-Value:get="GetCheckBoxState()"
                     @bind-Value:set="@(x => OnCheckboxChangedAsync())"
                     tabindex="-1"
                     aria-hidden="true" />
    }

    <div class="mud-list-item-text@(Inset ? " mud-list-item-text-inset" : string.Empty)">
        <MudText Typo="@TextTypo">
            @if (ChildContent != null)
            {
                @ChildContent
            }
            else
            {
                @Text
                @if (!string.IsNullOrEmpty(SecondaryText))
                {
                    <br />
                    <MudText Class="mud-list-item-secondary-text" Typo="Typo.subtitle2">
                        @SecondaryText
                    </MudText>
                }
            }
        </MudText>
    </div>

    @if (NestedList != null)
    {
        <MudIcon Disabled="@GetDisabled()"
                 Icon="@($"{(_expandedState.Value ? ExpandLessIcon : ExpandMoreIcon)}")"
                 Size="@IconSize"
                 Color="@ExpandIconColor" />
    }

</MudElement>

@if (NestedList != null)
{
    <MudCollapse Expanded="@_expandedState.Value">
        <MudList T="T"
                Class="mud-nested-list"
                Comparer="@Comparer"
                SelectionMode="@SelectionMode"
                ReadOnly="@ReadOnly"
                Color="@(MudList?.Color ?? Color.Primary)"
                Padding="false"
                Disabled="@GetDisabled()"
                Dense="@GetDense()"
                Gutters="@(MudList?.Gutters ?? true)">
            @NestedList
        </MudList>
    </MudCollapse>
}

